325→  switch (backend) {
326→    case 'claude':
327→      // Claude Code: --permission-mode and --allowedTools
328→      if (permissionMode && permissionMode !== 'default') {
329→        args.push('--permission-mode', permissionMode)
330→      }
331→      if (autoAcceptTools && autoAcceptTools.length > 0) {
332→        for (const tool of autoAcceptTools) {
333→          args.push('--allowedTools', tool)
334→        }
335→      }
336→      break
337→
338→    case 'gemini':
339→      // Gemini CLI: --approval-mode (default/auto_edit/yolo) and --allowed-tools
340→      // See: https://geminicli.com/docs/get-started/configuration/
341→      if (permissionMode) {
342→        switch (permissionMode) {
343→          case 'acceptEdits':
344→            args.push('--approval-mode', 'auto_edit')
345→            break
346→          case 'dontAsk':
347→          case 'bypassPermissions':
348→            args.push('--approval-mode', 'yolo')
349→            break
350→          // 'default' mode = no flag needed
351→        }
352→      }
353→      if (autoAcceptTools && autoAcceptTools.length > 0) {
354→        // Gemini uses comma-separated list for --allowed-tools
355→        args.push('--allowed-tools', autoAcceptTools.join(','))
356→      }
357→      break
358→
359→    case 'codex':
360→      // Codex CLI: --full-auto or --dangerously-bypass-approvals-and-sandbox
361→      // See: https://developers.openai.com/codex/cli/reference/
362→      if (permissionMode) {
363→        switch (permissionMode) {
364→          case 'acceptEdits':
365→          case 'dontAsk':
366→            args.push('--full-auto')
367→            break
368→          case 'bypassPermissions':
369→            args.push('--dangerously-bypass-approvals-and-sandbox')
370→            break
371→          // 'default' mode = no flag needed
372→        }
373→      }
374→      // Codex doesn't support per-tool auto-accept via CLI flags
375→      break
376→
377→    case 'opencode':
378→      // OpenCode doesn't accept permission flags on the CLI (use config instead).
379→      // Ignore auto-accept tools to avoid invalid arguments.
380→      break
381→
382→    case 'aider':
383→      // Aider doesn't have permission flags - it uses --yes for auto-confirm
384→      if (permissionMode && permissionMode !== 'default') {
385→        args.push('--yes')
