469→      sessionId,
470→      backend: backend as
471→        | 'claude'
472→        | 'gemini'
473→        | 'codex'
474→        | 'opencode'
475→        | 'aider'
476→        | undefined,
477→      disposables: [],
478→      spawnedAt: Date.now(),
479→      outputBuffer: new OutputBuffer(),
480→    }
481→
482→    this.processes.set(id, proc)
483→
484→    // Store disposables from onData/onExit for proper cleanup
485→    const dataDisposable = shell.onData(data => {
486→      proc.outputBuffer.append(data)
487→      const callback = this.dataCallbacks.get(id)
488→      if (callback) {
