513→  resize(id: string, cols: number, rows: number): void {
514→    const proc = this.processes.get(id)
515→    if (!proc) return
516→
517→    // Skip if dimensions haven't changed
518→    if (proc.lastResizeCols === cols && proc.lastResizeRows === rows) return
519→
520→    // Debounce resize events - Ink-based CLIs (e.g. Gemini) crash with
521→    // infinite re-render loops when they receive rapid SIGWINCH during startup
522→    if (proc.resizeTimeout) {
523→      clearTimeout(proc.resizeTimeout)
524→    }
525→
526→    const elapsed = Date.now() - proc.spawnedAt
527→    const isInkBackend = INK_BACKENDS.has(proc.backend || '')
528→    // During first 5s of Ink-backend startup, coalesce resizes with 1.5s debounce
529→    // to let the CLI finish initialization before sending SIGWINCH
