531→
532→    proc.resizeTimeout = setTimeout(() => {
533→      proc.resizeTimeout = undefined
534→      proc.lastResizeCols = cols
535→      proc.lastResizeRows = rows
536→      try {
537→        proc.pty.resize(cols, rows)
538→      } catch (e) {
539→        // PTY may have already exited, ignore resize errors
540→        console.log('PTY resize ignored (may have exited):', id)
541→      }
542→    }, debounceMs)
