549→      if (proc.resizeTimeout) {
550→        clearTimeout(proc.resizeTimeout)
551→        proc.resizeTimeout = undefined
552→      }
553→      // Dispose all event listeners first
554→      for (const disposable of proc.disposables) {
555→        try {
